const TAG_SUGGESTIONS = {"ワイシャツ":["仕事","営業","フォーマル","きれいめ"],"ドレスシャツ":["仕事","フォーマル","きれいめ"],"ポロシャツ":["夏","休日","クールビズ","カジュアル"],"スラックス":["仕事","営業","きれいめ"],"デニム":["休日","カジュアル"],"ジーンズ":["休日","カジュアル"],"ローファー":["仕事","営業","きれいめ","脱ぎやすい"],"スニーカー":["休日","旅行","長時間歩く"],"ランニングシューズ":["長時間歩く","旅行","運動"],"ウォーキングシューズ":["長時間歩く","旅行"],"レインシューズ":["雨","防水"]};

const makeBox = (patch={}) => ({
  id:crypto.randomUUID(), image:"", brand:"", productName:"", modelNumber:"", color:"その他",
  memo:"", linkedShoeId:"", createdAt:today(), ...patch
});

const makeItem = (kind, patch={}) => ({
  id: crypto.randomUUID(), kind, name:"", brand:"", color:"その他", image:"", favorite:false,
  useCount:0, lastUsed:"未使用", formal:3, tags:[LABEL[kind]], subtype:"未設定",
  sleeve:kind==="shirt"?"未設定":"", pattern:kind==="shoes"?"":"未設定", collar:"未設定", fit:"未設定",
  secondaryColor:"",colorConfidence:null,colorSource:"manual",
  length:kind==="pants"?"ロング":"", material:kind==="shoes"?"未設定":"",
  walk:3, easyOff:3, rain:"normal", maintenanceDate:"未実施", maintenanceCount:0,
  productName:"",modelNumber:"",store:"",purchaseDate:"",price:"",productURL:"",memo:"",
  tagPhoto:false,shoeBoxPhoto:false,maintenanceHistory:[],...patch
});

const samples = [
  makeItem("shirt",{id:"shirt-white",name:"白シャツ",brand:"無印良品",color:"白",subtype:"シャツ",sleeve:"長袖",pattern:"無地",formal:4,tags:["仕事","きれいめ"]}),
  makeItem("pants",{id:"pants-navy",name:"ネイビースラックス",brand:"UNIQLO",color:"ネイビー",subtype:"スラックス",formal:4,tags:["仕事","きれいめ"]}),
  makeItem("shoes",{id:"shoes-loafer",name:"黒ローファー",brand:"REGAL",color:"黒",subtype:"ローファー",material:"スムースレザー",formal:4,walk:4,easyOff:5,favorite:true,useCount:12,tags:["仕事","革靴","きれいめ"]}),
  makeItem("shoes",{id:"shoes-sneaker",name:"茶スニーカー",brand:"SKECHERS",color:"ブラウン",subtype:"スニーカー",material:"メッシュ",formal:2,walk:5,easyOff:4,rain:"bad",useCount:3,tags:["休日","歩きやすい"]}),
  makeItem("shoes",{id:"shoes-plain",name:"黒プレーントゥ",brand:"SCOTCH GRAIN",color:"黒",subtype:"プレーントゥ",material:"スムースレザー",formal:5,walk:3,rain:"good",useCount:6,tags:["仕事","フォーマル","雨"]})
];

let state = loadState();
let ui = {tab:"today",kind:"shirt",plan:"仕事",shirtId:"shirt-white",pantsId:"pants-navy",editing:null,boxEditing:null,karte:null,completion:null,registrationDone:null,nameSuggestions:[],extraCandidates:[],colorCandidates:[],colorConfirmed:false,captureMode:"tag"};
let weather = {area:"現在地",condition:"確認中",temperature:"--",rainChance:0,yesterday:"確認中"};
const app = document.querySelector("#app");

function loadState(){
  try { const saved=JSON.parse(localStorage.getItem(STORAGE_KEY)); if(saved?.items) return normalizeState(saved); } catch(e){}
  return normalizeState({items:samples,histories:[],boxes:[]});
}
function normalizeState(source){return {histories:Array.isArray(source.histories)?source.histories:[],boxes:Array.isArray(source.boxes)?source.boxes:[],items:(source.items||[]).map(i=>({
  productName:"",modelNumber:"",store:"",purchaseDate:"",price:"",productURL:"",memo:"",
  tagPhoto:false,shoeBoxPhoto:false,maintenanceHistory:[],secondaryColor:"",colorConfidence:null,colorSource:"manual",collar:"未設定",fit:"未設定",pattern:"未設定",...i,
  tags:Array.isArray(i.tags)?i.tags:[],maintenanceHistory:Array.isArray(i.maintenanceHistory)?i.maintenanceHistory:[]
}))};}
function saveState(){ try{localStorage.setItem(STORAGE_KEY,JSON.stringify(state));}catch(e){alert("写真が多すぎて保存できません。古い写真を減らしてください。");} }
function esc(v){return String(v??"").replace(/[&<>'"]/g,c=>({"&":"&amp;","<":"&lt;",">":"&gt;","'":"&#39;",'"':"&quot;"}[c]));}
function today(){return new Date().toLocaleDateString("ja-JP",{year:"numeric",month:"2-digit",day:"2-digit"}).replaceAll("/0","/");}
function itemPhoto(i){return i?.image?`<img class="photo" src="${i.image}" alt="${esc(i.name)}">`:`<div class="photo placeholder">${ICON[i?.kind]||"👞"}</div>`;}
function find(id){return state.items.find(x=>x.id===id);}

function render(){
  app.innerHTML=`<div class="shell"><header class="top"><div><p class="eyebrow">SHOES FIRST</p><h1>OUTFIT AI</h1></div><div class="weather">${weather.condition}　<strong>${weather.temperature}℃</strong><br><small>${weather.area}</small></div></header><main class="content">${view()}</main>${tabs()}</div>${ui.editing?editor(ui.editing):""}${ui.boxEditing?boxEditor(ui.boxEditing):""}${ui.registrationDone?registrationDoneView(ui.registrationDone):""}`;
  bind();
}
function tabs(){return `<nav class="tabs">${[["today","今日","☀️"],["master","マスター","▦"],["history","履歴","◷"],["analysis","気づき","◉"]].map(([id,label,icon])=>`<button data-tab="${id}" class="${ui.tab===id?"active":""}"><span>${icon}</span>${label}</button>`).join("")}</nav>`;}
function view(){if(ui.tab==="master")return masterView();if(ui.tab==="history")return historyView();if(ui.tab==="analysis")return analysisView();return todayView();}

function todayView(){
  if(ui.completion)return completionView();
  const shirts=state.items.filter(x=>x.kind==="shirt"), pants=state.items.filter(x=>x.kind==="pants"), shoes=state.items.filter(x=>x.kind==="shoes");
  const shirt=find(ui.shirtId)||shirts[0], pant=find(ui.pantsId)||pants[0];
  const results=scoreShoesV2(shoes,shirt,pant,ui.plan);
  const top=results[0];
  return `<div class="stack"><section class="today-outfit"><p class="eyebrow">TODAY'S OUTFIT</p><h2>今日のスタイリング</h2>${shirt&&pant&&top?`${outfitCharacter(shirt,pant,top.shoe)}<div class="outfit-illustration">${illustrationPiece("👔",shirt)}${illustrationPiece("👖",pant)}${illustrationPiece("👞",top.shoe)}</div><h3>${esc(top.shoe.name)}</h3><p class="today-reason">${esc(top.reason)}</p>`:`<div class="empty">マスターにシャツ・パンツ・靴を登録してください。</div>`}</section>
  <details class="panel conditions"><summary>今日の条件を変更</summary><div class="grid three"><label>予定<select id="plan">${PLANS.map(x=>`<option ${x===ui.plan?"selected":""}>${x}</option>`).join("")}</select></label><label>シャツ<select id="shirt">${shirts.map(x=>`<option value="${x.id}" ${x.id===shirt?.id?"selected":""}>${esc(x.name)}</option>`).join("")}</select></label><label>パンツ<select id="pants">${pants.map(x=>`<option value="${x.id}" ${x.id===pant?.id?"selected":""}>${esc(x.name)}</option>`).join("")}</select></label></div></details>
  ${results.length?`<section class="recommendations"><div class="section-title"><div><p class="eyebrow">TODAY'S PICKS</p><h3>今日のおすすめ3候補</h3></div></div>${results.map((r,i)=>recommendCard(r,i)).join("")}</section>`:""}
  <section class="panel"><div class="section-title"><div><p class="eyebrow">WHAT'S NEW</p><h3>新着情報</h3></div></div><div class="news-list">${buildNews().map(n=>`<div class="news-item"><span>${n.icon}</span><p>${esc(n.text)}</p></div>`).join("")}</div></section></div>`;
}
function outfitCharacter(shirt,pants,shoe){const s=colorCode(shirt.color),p=colorCode(pants.color),f=colorCode(shoe.color),short=shirt.sleeve==="半袖",cropped=/ショート/.test(pants.subtype)||pants.length==="ショート",wide=/ワイド|カーゴ/.test(pants.subtype)||pants.fit==="ワイド",polo=/ポロ/.test(shirt.subtype),tee=/Tシャツ/.test(shirt.subtype),open=/開襟/.test(shirt.subtype),sneaker=/スニーカー|ランニング|ウォーキング/.test(shoe.subtype),boot=/ブーツ|レイン/.test(shoe.subtype),sandal=/サンダル/.test(shoe.subtype),pattern=shirt.pattern||"未設定",desc=`${shirt.color}の${shirt.sleeve}${shirt.subtype}、${pants.color}の${pants.subtype}、${shoe.color}の${shoe.subtype}`;const patternSvg=pattern==="ドット"?`<pattern id="shirtPattern" width="12" height="12" patternUnits="userSpaceOnUse"><rect width="12" height="12" fill="${s}"/><circle cx="3" cy="3" r="1.7" fill="#fff" opacity=".75"/></pattern>`:pattern==="ストライプ"?`<pattern id="shirtPattern" width="10" height="10" patternUnits="userSpaceOnUse"><rect width="10" height="10" fill="${s}"/><path d="M3 0v10" stroke="#fff" opacity=".65" stroke-width="2"/></pattern>`:pattern==="チェック"?`<pattern id="shirtPattern" width="14" height="14" patternUnits="userSpaceOnUse"><rect width="14" height="14" fill="${s}"/><path d="M0 4h14M4 0v14" stroke="#fff" opacity=".5" stroke-width="2"/></pattern>`:pattern==="ボーダー"?`<pattern id="shirtPattern" width="12" height="12" patternUnits="userSpaceOnUse"><rect width="12" height="12" fill="${s}"/><path d="M0 4h12" stroke="#fff" opacity=".65" stroke-width="3"/></pattern>`:"";const shirtFill=patternSvg?"url(#shirtPattern)":s;const shoeShape=sandal?`<path d="M72 229h36v9H72zM112 229h38v9h-38z" fill="${f}"/><path d="M81 221q14 8 22 10M121 222q15 7 23 9" stroke="${f}" stroke-width="6" fill="none"/>`:boot?`<path d="M78 207h28l3 31H70q0-13 8-18zM116 207h27l9 31h-40z" fill="${f}" stroke="#243128" stroke-width="3"/>`:sneaker?`<path d="M78 220q18-5 31 8v11H68q-2-13 10-19M119 220q22 0 33 11v8h-42q-1-13 9-19" fill="${f}" stroke="#243128" stroke-width="3"/><path d="M76 232h32M116 232h34" stroke="#fff" stroke-width="3"/>`:`<path d="M80 220q18-4 28 8v11H70q-1-13 10-19M120 220q20 0 30 10v9h-39q0-13 9-19" fill="${f}" stroke="#243128" stroke-width="3"/><path d="M83 224h18M122 225h19" stroke="#d9bd82" stroke-width="2"/>`;return `<div class="stylist-character improved" aria-label="${esc(desc)}"><svg viewBox="0 0 220 260" role="img"><defs>${patternSvg}<filter id="softShadow"><feDropShadow dx="0" dy="4" stdDeviation="4" flood-opacity=".18"/></filter></defs><ellipse cx="110" cy="244" rx="58" ry="9" fill="#17231d" opacity=".12"/><g filter="url(#softShadow)"><path d="M92 63h36v22H92z" fill="#efbd98"/><circle cx="110" cy="40" r="30" fill="#f3c9a8"/><path d="M80 38q4-35 37-34q31 1 27 38q-12-16-32-17q-18 0-32 13" fill="#44352d"/><path d="M84 29q9-19 28-20q23 0 31 23q-15-10-31-10q-15 0-28 7" fill="#514037"/><circle cx="99" cy="42" r="3" fill="#272925"/><circle cx="121" cy="42" r="3" fill="#272925"/><path d="M102 55q8 7 17 0" fill="none" stroke="#a55f58" stroke-width="2.5" stroke-linecap="round"/><circle cx="88" cy="51" r="4" fill="#e8a89b" opacity=".45"/><circle cx="132" cy="51" r="4" fill="#e8a89b" opacity=".45"/><path d="M84 78L${short?"64 111 78 121":"54 139 72 147"}L90 102V162H130V102L${short?"142 121 157 111":"148 147 166 139"}L136 78Z" fill="${shirtFill}" stroke="#243128" stroke-width="3" stroke-linejoin="round"/>${polo?`<path d="M98 78l12 12l12-12M110 88v20" fill="none" stroke="#243128" stroke-width="3"/><circle cx="110" cy="96" r="2"/>`:tee?`<path d="M98 79q12 13 24 0" fill="none" stroke="#243128" stroke-width="3"/>`:open?`<path d="M96 79l14 17l14-17" fill="#f7f7f4" stroke="#243128" stroke-width="2"/>`:`<path d="M95 78l15 15l15-15M110 92v67" fill="none" stroke="#243128" stroke-width="2.5"/><circle cx="110" cy="107" r="2"/><circle cx="110" cy="122" r="2"/>`}<circle cx="${short?69:60}" cy="${short?113:143}" r="7" fill="#f3c9a8"/><circle cx="${short?152:160}" cy="${short?113:143}" r="7" fill="#f3c9a8"/><path d="M89 160L${cropped?wide?"78 202 104 202":"87 204 105 204":wide?"75 226 103 226":"87 226 105 226"}L110 176L116 ${cropped?"204":"226"}L${wide?"145":"133"} ${cropped?"204":"226"}L131 160Z" fill="${p}" stroke="#243128" stroke-width="3" stroke-linejoin="round"/>${/デニム|ジーンズ/.test(pants.subtype)?`<path d="M91 166h38M110 176v48" stroke="#d8b66b" stroke-width="2" opacity=".75"/>`:""}${/カーゴ/.test(pants.subtype)?`<path d="M79 181h24v18H79zM118 181h24v18h-24z" fill="none" stroke="#243128" stroke-width="2"/>`:""}${shoeShape}</g></svg><span>今日のコーデ</span></div>`;}
function illustrationPiece(icon,item){return `<div><span class="color-orb" style="--item-color:${colorCode(item.color)}">${icon}</span><b>${esc(item.name)}</b></div>`;}
function colorCode(color){return ({"白":"#f7f7f4","黒":"#252724","グレー":"#929792","ネイビー":"#263958","青":"#4984b8","水色":"#8bc5df","ベージュ":"#d7bc8e","ブラウン":"#7f563e","グリーン":"#58785a","カーキ":"#77734f","赤":"#a94a46","ワイン":"#722f45","ピンク":"#d98da5","イエロー":"#e1bb45","オレンジ":"#d77b37","パープル":"#745b91","その他":"#bab7ae"})[color]||"#bab7ae";}
function daysSince(text){if(!text||text==="未使用"||text==="未実施")return null;const d=new Date(text.replaceAll("/","-"));if(Number.isNaN(d.getTime()))return null;return Math.max(0,Math.floor((Date.now()-d.getTime())/86400000));}
function completeness(i){const linkedBox=i.kind==="shoes"&&(state.boxes||[]).some(b=>b.linkedShoeId===i.id);let score=0;if(i.image)score+=20;if(i.name)score+=10;if(i.color&&i.color!=="その他")score+=10;if(i.subtype&&i.subtype!=="未設定")score+=10;if(i.brand)score+=10;const specific=i.kind==="shirt"?(i.sleeve!=="未設定"||i.pattern!=="未設定"):i.kind==="pants"?(i.length||i.pattern!=="未設定"):(i.material!=="未設定"||i.rain!=="normal");if(specific)score+=10;if(i.tags?.length)score+=5;if(i.productName||i.modelNumber)score+=10;if(i.store||i.purchaseDate||i.price)score+=5;if(i.memo)score+=5;if(i.tagPhoto)score+=3;if(i.kind!=="shoes"||i.shoeBoxPhoto||linkedBox)score+=2;return Math.min(100,score);}
function buildNews(){const news=[];if(weather.condition==="雨"||weather.rainChance>=50)news.push({icon:"🌧",text:`今日は雨の可能性があります（降水確率 ${weather.rainChance}%）`});const shoes=state.items.filter(i=>i.kind==="shoes");const never=shoes.find(i=>i.useCount===0);if(never)news.push({icon:"✨",text:`${never.name}はまだ一度も履いていません`});const sleeping=shoes.map(i=>({i,days:daysSince(i.lastUsed)})).filter(x=>x.days!==null&&x.days>=30).sort((a,b)=>b.days-a.days)[0];if(sleeping)news.push({icon:"👞",text:`${sleeping.i.name}は${sleeping.days}日履いていません`});const care=shoes.find(i=>(i.maintenanceHistory||[]).length===0||daysSince(i.maintenanceDate)>=30);if(care)news.push({icon:"🧴",text:`${care.name}のお手入れ時期を確認しませんか`});const incomplete=state.items.filter(i=>completeness(i)<80).sort((a,b)=>completeness(a)-completeness(b))[0];if(incomplete)news.push({icon:"📋",text:`${incomplete.name||LABEL[incomplete.kind]}の情報を追加するとカルテが育ちます`});const box=(state.boxes||[]).find(b=>!b.linkedShoeId);if(box)news.push({icon:"📦",text:`${box.productName||box.brand||"登録した靴箱"}が靴と未関連です`});return news.slice(0,5).length?news.slice(0,5):[{icon:"✓",text:"今日も靴を楽しみましょう"}];}
function recommendCard(r,i){const days=daysSince(r.shoe.lastUsed),interval=days===null?"未使用":days===0?"本日使用済み":`${days}日ぶり`;const stars=Math.max(1,Math.min(5,Math.round(r.score/20)));return `<article class="card recommendation ${i===0?"best":""}"><div class="rank">${i+1}</div>${itemPhoto(r.shoe)}<div><div class="score"><b>${esc(r.shoe.name)}</b><strong>${r.score}<small>点</small></strong></div><div class="stars" aria-label="おすすめ度${stars}つ">${"★".repeat(stars)}${"☆".repeat(5-stars)}</div><p>${esc(r.reason)}</p><small class="interval">使用間隔：${interval}</small><button class="${i===0?"primary":"secondary"} wear" data-id="${r.shoe.id}" data-reason="${esc(r.reason)}">今日これを履く</button></div></article>`;}

function patternCount(...items){return items.filter(i=>i&&i.pattern&&!['未設定','無地','デニム'].includes(i.pattern)).length;}
function scoreShoesV2(shoes,shirt,pants,plan){const basic=["黒","白","ブラウン","ネイビー","グレー","ベージュ"];return shoes.map(shoe=>{let score=45,reasons=[];if(["仕事","営業","フォーマル"].includes(plan)){shoe.formal>=4?(score+=18,reasons.push("予定に合うフォーマル度")):(score-=12,reasons.push("少しカジュアル"));if(/ワイシャツ|ドレスシャツ|ビジネスシャツ/.test(shirt?.subtype||"")&&/ローファー|プレーントゥ|ストレートチップ|ビジネス/.test(shoe.subtype)){score+=8;reasons.push("シャツと革靴の相性");}}if(plan==="休日"&&shoe.formal<=3){score+=10;reasons.push("休日向き");if(/ポロシャツ|Tシャツ/.test(shirt?.subtype||"")&&/スニーカー|スリッポン/.test(shoe.subtype)){score+=8;reasons.push("軽快な休日スタイル");}}if(plan==="長時間歩く"){score+=shoe.walk*5;if(/ランニング|ウォーキング/.test(shoe.subtype))score+=10;reasons.push("歩きやすさを重視");}if(weather.rainChance>=50||plan==="雨"){if(shoe.rain==="good"||/レイン/.test(shoe.subtype)){score+=22;reasons.push("雨に強い");}if(shoe.rain==="bad"){score-=28;reasons.push("雨には不向き");}if(shoe.material==="スエード"){score-=22;reasons.push("雨の日はスエードを避けたい");}}if(shirt?.color==="白"&&shoe.color==="黒"){score+=8;reasons.push("白と黒の好相性");}if(pants?.color==="ネイビー"&&["黒","ブラウン"].includes(shoe.color)){score+=8;reasons.push("ネイビーパンツに調和");}if(/スラックス/.test(pants?.subtype||"")&&/ローファー|ビジネス|プレーントゥ|ストレートチップ/.test(shoe.subtype)){score+=7;reasons.push("スラックスに合う");}if(/デニム|ジーンズ/.test(pants?.subtype||"")&&/スニーカー/.test(shoe.subtype)){score+=7;reasons.push("デニムに合う");}if(patternCount(shirt,pants)>=2&&basic.includes(shoe.color)){score+=7;reasons.push("柄を引き立てるベーシックカラー");}if(shoe.favorite){score+=6;reasons.push("お気に入り");}const rest=daysSince(shoe.lastUsed);if(shoe.useCount===0){score+=8;reasons.push("まだ履いていない");}else if(rest!==null&&rest>=7){score+=Math.min(8,Math.floor(rest/7)*2);reasons.push(`${rest}日休ませた一足`);}if(shoe.lastUsed===today()){score-=28;reasons.push("今日は使用済み");}return{shoe,score:Math.max(0,Math.min(100,score)),reason:[...new Set(reasons)].slice(0,5).join("・")||"全体のバランスが良い"};}).sort((a,b)=>b.score-a.score).slice(0,3);}

function completionView(){const c=ui.completion;return `<section class="completion"><div class="check">✓</div><p class="eyebrow">TODAY'S OUTFIT</p><h2>今日のコーデを記録しました</h2>${outfitCharacter(c.shirt,c.pants,c.shoe)}<p class="muted">${esc(weather.condition)}・${weather.temperature}℃</p><div class="outfit">${outfitPiece(c.shirt,"シャツ")}${outfitPiece(c.pants,"パンツ")}${outfitPiece(c.shoe,"靴")}</div><div class="panel"><b>この靴を選んだ理由</b><p>${esc(c.reason)}</p></div><div class="actions completion-actions"><button id="home" class="primary">ホームへ戻る</button><button id="completionHistory" class="secondary">履歴を見る</button></div></section>`;}
function outfitPiece(i,label){return `<div>${itemPhoto(i)}<small>${label}</small><br><b>${esc(i.name)}</b></div>`;}

function masterView(){const list=state.items.filter(x=>x.kind===ui.kind),boxes=state.boxes||[];return `<div class="stack"><div class="section-title"><div><p class="eyebrow">WARDROBE</p><h2>マスター</h2></div><div class="mini-actions">${ui.kind==="shoes"?`<button id="addBox" class="secondary">📦 箱だけ登録</button>`:""}<button id="add" class="primary">＋ 登録</button></div></div><div class="segmented">${["shirt","pants","shoes"].map(k=>`<button class="kind ${ui.kind===k?"active":""}" data-kind="${k}">${ICON[k]} ${LABEL[k]}</button>`).join("")}</div><section class="master-grid">${list.map(i=>`<article class="card item-card">${itemPhoto(i)}<div class="item-copy"><b>${esc(i.name)} ${i.favorite?"★":""}</b><p>${esc(i.brand||"ブランド未設定")} / ${esc(i.color)}</p><small>${esc(i.subtype)}${i.kind==="shoes"?`・${esc(i.material)}・歩きやすさ${i.walk}`:""}</small><small>使用 ${i.useCount}回・最終 ${esc(i.lastUsed)}</small><div class="mini-actions"><button class="secondary edit" data-id="${i.id}">編集</button><button class="primary karte" data-id="${i.id}">カルテ</button></div></div></article>`).join("")||`<div class="empty">まだ登録されていません</div>`}</section>${ui.kind==="shoes"&&boxes.length?`<section class="panel"><div class="section-title"><h3>靴箱</h3><span>${boxes.filter(b=>!b.linkedShoeId).length}件 未関連</span></div><div class="box-list">${boxes.map(boxCard).join("")}</div></section>`:""}</div>${ui.karte?karteView(ui.karte):""}`;}
function boxCard(box){const shoe=find(box.linkedShoeId);return `<button class="box-card edit-box" data-id="${box.id}">${box.image?`<img class="photo" src="${box.image}" alt="靴箱">`:`<span class="box-placeholder">📦</span>`}<span><b>${esc(box.productName||box.brand||"名称未設定の靴箱")}</b><small>${shoe?`${esc(shoe.name)}と関連済み`:"未関連"}</small></span><strong>${shoe?"✓":"関連付け"}</strong></button>`;}


function editor(item){
  const exists=state.items.some(x=>x.id===item.id),types=TYPES[item.kind],brands=BRANDS[item.kind],tagOptions=TAG_SUGGESTIONS[item.subtype]||[];
  const previewName=item.name||(item.color+(item.subtype==="未設定"?LABEL[item.kind]:item.subtype));
  const colorChoices=ui.colorCandidates.map(c=>`<button class="color-choice ${c.name===item.color?"selected":""}" data-color="${c.name}" data-confidence="${c.confidence}"><span style="--chip:${colorCode(c.name)}"></span><b>${c.name}</b><small>${c.confidence}%</small></button>`).join("");
  const typeChips=types.slice(0,8).map(x=>`<button class="type-choice ${x===item.subtype?"selected":""}" data-value="${x}">${x}</button>`).join("");
  const brandChips=brands.slice(0,7).map(x=>`<button class="brand-choice ${x===item.brand?"selected":""}" data-value="${esc(x)}">${esc(x)}</button>`).join("");
  const nameChoices=ui.nameSuggestions.map((n,i)=>`<button class="name-choice secondary" data-name="${esc(n)}"><small>${i===0?"管理":i<3?"おしゃれ":"遊び"}</small>${esc(n)}</button>`).join("");
  const tagChoices=tagOptions.map(x=>`<button class="tag-choice ${(item.tags||[]).includes(x)?"selected":""}" data-value="${x}">${x}</button>`).join("");
  const candidates=ui.extraCandidates.map((c,i)=>`<label><input class="candidate" type="checkbox" data-index="${i}"> ${esc(c.label)}：${esc(c.value)}</label>`).join("");
  return `<div class="modal"><section class="editor quick-editor"><div class="editor-head"><div><p class="eyebrow">QUICK REGISTER</p><h2>${LABEL[item.kind]}をサッと登録</h2></div><button id="close" class="secondary">閉じる</button></div>
  <div class="register-steps five"><span class="${item.image?"done":""}">1 写真</span><span class="${item.color&&item.color!=="その他"?"done":""}">2 色</span><span class="${item.subtype!=="未設定"?"done":""}">3 種類</span><span class="${item.name?"done":""}">4 名前</span><span>5 完了</span></div>
  <div class="photo-stage">${item.image?`<img src="${item.image}" alt="登録写真">`:`<div class="empty">${ICON[item.kind]}<br>写真はあとからでも追加できます</div>`}</div><div class="photo-actions"><button id="camera" class="secondary">📷 撮影</button><button id="library" class="secondary">写真を選択・変更</button></div><input id="cameraInput" class="hidden" type="file" accept="image/*" capture="environment"><input id="libraryInput" class="hidden" type="file" accept="image/*">
  <details class="shooting-guide"><summary>色をきれいに判定するコツ</summary><p>明るい場所・無地の背景で、アイテム全体を中央に入れ、強い影や反射を避けてください。</p></details>
  <section class="quick-section"><b>1. 実物に近い色</b>${ui.colorCandidates.length?`<p class="muted">写真から近い色を見つけました。候補は自動確定されません。</p><div class="color-candidates">${colorChoices}</div>`:`<p class="muted">写真を選ぶか、一覧から色を選んでください。</p>`}<label>全色から選択<select id="color">${COLORS.map(x=>`<option ${x===item.color?"selected":""}>${x}</option>`).join("")}</select></label><label>サブ色（任意）<select id="secondaryColor"><option value="">なし</option>${COLORS.filter(x=>x!=="その他").map(x=>`<option ${x===item.secondaryColor?"selected":""}>${x}</option>`).join("")}</select></label></section>
  <section class="quick-section"><b>2. 種類</b><div class="quick-chips">${typeChips}</div><label>候補または自由入力<input id="subtype" list="typeList" value="${esc(item.subtype==="未設定"?"":item.subtype)}" placeholder="種類を選択・入力"><datalist id="typeList">${types.map(x=>`<option value="${x}">`).join("")}</datalist></label></section>
  <section class="quick-section"><b>3. ブランド（任意）</b><div class="quick-chips brand-chips">${brandChips}</div><label>候補または自由入力<input id="brand" list="brandList" value="${esc(item.brand)}" placeholder="未設定でも保存できます"><datalist id="brandList">${brands.map(x=>`<option value="${esc(x)}">`).join("")}</datalist></label></section>
  <section class="quick-section"><b>4. 名前</b><label>名称（自由に修正できます）<input id="name" value="${esc(item.name)}" placeholder="色と種類から自動作成"></label><button id="suggestName" class="suggest-button">✨ 名称提案</button>${ui.nameSuggestions.length?`<div class="suggestion-groups"><small>管理向け・おしゃれ・遊び</small><div class="suggestions">${nameChoices}</div></div>`:""}</section>
  <section class="register-preview">${itemPhoto(item)}<div><small>登録プレビュー</small><h3>${esc(previewName)}</h3><p>${esc(item.brand||"ブランド未設定")}・${esc(item.color)}・${esc(item.subtype)}</p><strong>カルテ充実度 ${completeness(item)}%</strong></div></section>
  <details class="panel grow-details"><summary>あとで情報を育てる</summary><div class="grid"><label>フォーマル度：<span id="formalValue">${item.formal}</span><input id="formal" type="range" min="1" max="5" value="${item.formal}"></label>${typeFields(item)}<label>自由タグ（読点区切り）<input id="tags" value="${esc((item.tags||[]).join("、"))}"></label>${tagOptions.length?`<div><small>おすすめタグ</small><div class="quick-chips">${tagChoices}</div></div>`:""}<label><input id="favorite" type="checkbox" ${item.favorite?"checked":""}> お気に入り</label></div>
  <div class="panel inner-panel"><b>写真から情報を追加</b><p class="muted">採用した候補だけ反映します。</p><div class="actions"><button id="tagPhoto" class="secondary">タグを撮影</button>${item.kind==="shoes"?`<button id="shoeBox" class="secondary">靴箱を撮影</button>`:""}</div><input id="tagInput" class="hidden" type="file" accept="image/*" capture="environment">${ui.extraCandidates.length?`<div class="candidate-box">${candidates}</div>`:""}</div>
  <div class="grid purchase-fields"><label>商品名<input id="productName" value="${esc(item.productName)}"></label><label>型番<input id="modelNumber" value="${esc(item.modelNumber)}"></label><label>購入店<input id="store" value="${esc(item.store)}"></label><label>購入日<input id="purchaseDate" type="date" value="${esc(item.purchaseDate)}"></label><label>価格<input id="price" inputmode="numeric" value="${esc(item.price)}"></label><label>商品URL<input id="productURL" type="url" value="${esc(item.productURL)}"></label><label>メモ<textarea id="memo">${esc(item.memo)}</textarea></label></div></details>
  <div class="actions sticky-actions">${exists?`<button id="delete" class="danger">削除</button>`:""}<button id="cancel" class="secondary">キャンセル</button><button id="save" class="primary">${exists?"更新":"この内容で登録"}</button></div></section></div>`;
}

function registrationDoneView(item){return `<div class="modal"><section class="editor registration-done"><div class="celebrate">✨</div><p class="eyebrow">WELCOME TO YOUR WARDROBE</p><h2>${item.kind==="shoes"?"新しい一足が仲間入りしました！":"新しいアイテムが仲間入りしました！"}</h2>${itemPhoto(item)}<h3>${esc(item.name)}</h3><p>${esc(item.brand||"ブランド未設定")}・${esc(item.color)}・${esc(item.subtype)}</p><div class="completeness"><div><b>カルテ充実度</b><strong>${completeness(item)}%</strong></div><progress max="100" value="${completeness(item)}"></progress><small>詳細情報はいつでも後から育てられます。</small></div><div class="actions"><button id="doneToday" class="primary">今日のコーデで使う</button><button id="doneKarte" class="secondary">カルテを見る</button><button id="doneAnother" class="secondary">続けて登録</button><button id="doneMaster" class="secondary">マスターへ戻る</button></div></section></div>`;}

function boxEditor(box){const shoes=state.items.filter(i=>i.kind==="shoes");return `<div class="modal"><section class="editor"><div class="editor-head"><div><p class="eyebrow">SHOE BOX</p><h2>箱だけ登録</h2></div><button id="closeBox" class="secondary">閉じる</button></div><p class="muted">靴が手元になくても登録できます。後から確認して関連付けてください。</p><div class="photo-stage">${box.image?`<img src="${box.image}" alt="靴箱写真">`:`<div class="empty">📦<br>靴箱を撮影・選択してください</div>`}</div><div class="photo-actions"><button id="boxCamera" class="secondary">📷 カメラで撮影</button><button id="boxLibrary" class="secondary">写真を選択・変更</button></div><input id="boxCameraInput" class="hidden" type="file" accept="image/*" capture="environment"><input id="boxLibraryInput" class="hidden" type="file" accept="image/*"><div class="grid"><label>ブランド<input id="boxBrand" value="${esc(box.brand)}"></label><label>商品名<input id="boxProductName" value="${esc(box.productName)}"></label><label>型番<input id="boxModelNumber" value="${esc(box.modelNumber)}"></label><label>箱の色<select id="boxColor">${COLORS.map(x=>`<option ${x===box.color?"selected":""}>${x}</option>`).join("")}</select></label><label>靴との関連付け<select id="linkedShoeId"><option value="">未関連のまま保存</option>${shoes.map(i=>`<option value="${i.id}" ${i.id===box.linkedShoeId?"selected":""}>${esc(i.name)}</option>`).join("")}</select></label><label>メモ<textarea id="boxMemo">${esc(box.memo)}</textarea></label></div><p class="muted">自動関連付けは行いません。選択した靴だけに関連付けます。</p><div class="actions"><button id="deleteBox" class="danger">削除</button><button id="saveBox" class="primary">保存</button></div></section></div>`;}
function typeFields(i){if(i.kind==="shirt")return `<label>袖<select id="sleeve">${["未設定","半袖","長袖","七分袖","ノースリーブ"].map(x=>`<option ${x===i.sleeve?"selected":""}>${x}</option>`).join("")}</select></label><label>襟<select id="collar">${["未設定","レギュラー","ボタンダウン","ワイド","開襟","スタンド","襟なし"].map(x=>`<option ${x===i.collar?"selected":""}>${x}</option>`).join("")}</select></label><label>柄<select id="pattern">${PATTERNS.shirt.map(x=>`<option ${x===i.pattern?"selected":""}>${x}</option>`).join("")}</select></label><label>フィット<select id="fit">${["未設定","スリム","標準","ゆったり"].map(x=>`<option ${x===i.fit?"selected":""}>${x}</option>`).join("")}</select></label>`;if(i.kind==="pants")return `<label>丈<select id="length">${["ロング","アンクル","クロップド","ショート"].map(x=>`<option ${x===i.length?"selected":""}>${x}</option>`).join("")}</select></label><label>柄<select id="pattern">${PATTERNS.pants.map(x=>`<option ${x===i.pattern?"selected":""}>${x}</option>`).join("")}</select></label><label>フィット<select id="fit">${["未設定","スリム","標準","ワイド"].map(x=>`<option ${x===i.fit?"selected":""}>${x}</option>`).join("")}</select></label>`;return `<label>素材<select id="material">${["未設定","スムースレザー","スエード","キャンバス","メッシュ","合皮"].map(x=>`<option ${x===i.material?"selected":""}>${x}</option>`).join("")}</select></label><label>雨対応<select id="rain"><option value="good" ${i.rain==="good"?"selected":""}>強い</option><option value="normal" ${i.rain==="normal"?"selected":""}>普通</option><option value="bad" ${i.rain==="bad"?"selected":""}>弱い</option></select></label><label>歩きやすさ：<span id="walkValue">${i.walk}</span><input id="walk" type="range" min="1" max="5" value="${i.walk}"></label><label>脱ぎやすさ：<span id="easyOffValue">${i.easyOff}</span><input id="easyOff" type="range" min="1" max="5" value="${i.easyOff}"></label>`;}

function karteView(item){const percent=completeness(item),linkedBox=item.kind==="shoes"&&(state.boxes||[]).some(b=>b.linkedShoeId===item.id);return `<div class="modal"><section class="editor karte-sheet"><div class="editor-head"><div><p class="eyebrow">ITEM RECORD</p><h2>${esc(item.name)}のカルテ</h2></div><button id="closeKarte" class="secondary">閉じる</button></div><div class="karte-hero">${itemPhoto(item)}<div><b>${esc(item.brand||"ブランド未設定")}</b><h3>${esc(item.productName||item.name)}</h3><p>${esc(item.modelNumber||"型番未設定")}</p></div></div><div class="completeness"><div><b>情報充実度</b><strong>${percent}%</strong></div><progress max="100" value="${percent}"></progress><div class="check-list"><span>写真 ${item.image?"✅":"未登録"}</span><span>タグ ${item.tagPhoto?"✅":"未登録"}</span>${item.kind==="shoes"?`<span>靴箱 ${item.shoeBoxPhoto||linkedBox?"✅":"未登録"}</span>`:""}</div></div><section class="karte-data"><p><b>購入店</b>${esc(item.store||"未設定")}</p><p><b>購入日</b>${esc(item.purchaseDate||"未設定")}</p><p><b>価格</b>${item.price?`${esc(item.price)}円`:"未設定"}</p><p><b>使用回数</b>${item.useCount}回</p><p><b>最終使用日</b>${esc(item.lastUsed)}</p><p><b>タグ</b>${esc((item.tags||[]).join("・")||"未設定")}</p><p><b>メモ</b>${esc(item.memo||"未設定")}</p>${item.productURL?`<p><b>商品URL</b><a href="${esc(item.productURL)}" target="_blank" rel="noopener">開く</a></p>`:""}</section>${item.kind==="shoes"?`<section class="panel"><h3>ワンタップメンテナンス</h3><div class="maintenance-buttons">${["ブラッシング","クリーム","防水","ソール清掃","丸洗い"].map(t=>`<button class="secondary maintenance-action" data-type="${t}">${t}</button>`).join("")}</div><div class="maintenance-log">${(item.maintenanceHistory||[]).slice(0,5).map(m=>`<small>${esc(m.date)}　${esc(m.type)}</small>`).join("")||`<small>まだ記録はありません</small>`}</div></section><section class="panel"><h3>56日 使用・ケアカレンダー</h3><div class="calendar-legend"><span>👞 着用</span><span>🧴 メンテ</span><span>🌧 雨の日使用</span></div>${activityCalendar(item)}</section>`:""}<div class="actions">${item.kind==="shoes"?`<button id="wearFromKarte" class="primary">今日履く</button>`:""}<button id="historyFromKarte" class="secondary">履歴</button><button id="editFromKarte" class="secondary">編集</button></div></section></div>`;}
function activityCalendar(item){const days=[];for(let n=55;n>=0;n--){const d=new Date();d.setDate(d.getDate()-n);const key=d.toLocaleDateString("ja-JP",{year:"numeric",month:"2-digit",day:"2-digit"}).replaceAll("/0","/");const wears=state.histories.filter(h=>h.date===key&&((item.kind==="shoes"&&h.shoes===item.name)||(item.kind==="shirt"&&h.shirt===item.name)||(item.kind==="pants"&&h.pants===item.name)));const maintenance=(item.maintenanceHistory||[]).some(m=>m.date===key);const rainy=wears.some(h=>h.weather.includes("雨"));days.push(`<span class="activity ${maintenance?"care":rainy?"rain":wears.length?"worn":""}" title="${key}"></span>`);}return `<div class="activity-grid">${days.join("")}</div>`;}

function historyView(){return `<div class="stack"><div class="section-title"><div><p class="eyebrow">JOURNAL</p><h2>コーデ履歴</h2></div><span>${state.histories.length}件</span></div><section class="timeline">${state.histories.map(h=>`<article class="history"><b>${esc(h.date)}　${esc(h.shoes)}</b><p>${esc(h.shirt)}・${esc(h.pants)}</p><small>${esc(h.plan)} / ${esc(h.weather)}</small><small>${esc(h.reason)}</small></article>`).join("")||`<div class="empty">「今日これを履く」を押すと、ここに記録されます。</div>`}</section></div>`;}
function analysisView(){const shoes=state.items.filter(x=>x.kind==="shoes"),sleeping=shoes.map(i=>({i,days:daysSince(i.lastUsed)})).filter(x=>x.days===null||x.days>=30).sort((a,b)=>(b.days||999)-(a.days||999)),care=shoes.filter(i=>!(i.maintenanceHistory||[]).length||daysSince(i.maintenanceDate)>=30),incomplete=state.items.filter(i=>completeness(i)<80).sort((a,b)=>completeness(a)-completeness(b));return `<div class="stack"><div class="section-title"><div><p class="eyebrow">INSIGHTS</p><h2>次の行動につながる気づき</h2></div></div><section class="panel"><h3>眠っている一足</h3>${sleeping.slice(0,3).map(x=>insightCard(x.i,"👞",x.days===null?"まだ履いていません":`${x.days}日履いていません`)).join("")||`<p class="muted">靴はバランスよく活躍しています。</p>`}</section><section class="panel"><h3>メンテナンス提案</h3>${care.slice(0,3).map(i=>insightCard(i,"🧴",(i.maintenanceHistory||[]).length?`最終手入れから${daysSince(i.maintenanceDate)}日`:`手入れの記録を始めませんか`)).join("")||`<p class="muted">現在、急ぎの提案はありません。</p>`}</section><section class="panel"><h3>カルテを育てる</h3>${incomplete.slice(0,3).map(i=>insightCard(i,"✨",`情報充実度 ${completeness(i)}%`)).join("")||`<p class="muted">登録情報は十分に充実しています。</p>`}</section></div>`;}
function insightCard(item,icon,text){return `<button class="insight-card karte" data-id="${item.id}"><span>${icon}</span>${itemPhoto(item)}<div><b>${esc(item.name)}</b><small>${esc(text)}</small></div><strong>カルテへ</strong></button>`;}

function bind(){
  document.querySelectorAll("[data-tab]").forEach(b=>b.onclick=()=>{ui.tab=b.dataset.tab;ui.completion=null;render();});
  const plan=document.querySelector("#plan");if(plan)plan.onchange=e=>{ui.plan=e.target.value;render();};
  const shirt=document.querySelector("#shirt");if(shirt)shirt.onchange=e=>{ui.shirtId=e.target.value;render();};
  const pants=document.querySelector("#pants");if(pants)pants.onchange=e=>{ui.pantsId=e.target.value;render();};
  document.querySelectorAll(".wear").forEach(b=>b.onclick=()=>recordWear(b.dataset.id,b.dataset.reason));
  const home=document.querySelector("#home");if(home)home.onclick=()=>{ui.completion=null;render();};
  const completionHistory=document.querySelector("#completionHistory");if(completionHistory)completionHistory.onclick=()=>{ui.completion=null;ui.tab="history";render();};
  document.querySelectorAll(".kind").forEach(b=>b.onclick=()=>{ui.kind=b.dataset.kind;render();});
  const add=document.querySelector("#add");if(add)add.onclick=()=>{ui.nameSuggestions=[];ui.extraCandidates=[];ui.colorCandidates=[];ui.colorConfirmed=false;ui.editing=makeItem(ui.kind);render();};
  const addBox=document.querySelector("#addBox");if(addBox)addBox.onclick=()=>{ui.boxEditing=makeBox();render();};
  document.querySelectorAll(".edit-box").forEach(b=>b.onclick=()=>{ui.boxEditing=structuredClone((state.boxes||[]).find(x=>x.id===b.dataset.id));render();});
  document.querySelectorAll(".edit").forEach(b=>b.onclick=()=>{ui.karte=null;ui.nameSuggestions=[];ui.extraCandidates=[];ui.colorCandidates=[];ui.colorConfirmed=true;ui.editing=structuredClone(find(b.dataset.id));render();});
  document.querySelectorAll(".karte").forEach(b=>b.onclick=()=>{ui.karte=find(b.dataset.id);render();});
  if(ui.karte)bindKarte();
  if(ui.editing)bindEditor();
  if(ui.boxEditing)bindBoxEditor();
  if(ui.registrationDone)bindRegistrationDone();
}
function recordWear(id,reason){const shoe=find(id),shirt=find(ui.shirtId),pants=find(ui.pantsId);if(!shoe||!shirt||!pants)return;shoe.useCount++;shoe.lastUsed=today();state.histories.unshift({id:crypto.randomUUID(),date:today(),plan:ui.plan,weather:`${weather.condition} ${weather.temperature}℃`,shirt:shirt.name,pants:pants.name,shoes:shoe.name,reason});ui.completion={shoe:structuredClone(shoe),shirt,pants,reason};saveState();render();}

function bindEditor(){
  const close=()=>{ui.editing=null;render();};document.querySelector("#close").onclick=close;document.querySelector("#cancel").onclick=close;
  document.querySelector("#camera").onclick=()=>document.querySelector("#cameraInput").click();document.querySelector("#library").onclick=()=>document.querySelector("#libraryInput").click();
  document.querySelector("#cameraInput").onchange=photoChanged;document.querySelector("#libraryInput").onchange=photoChanged;
  const tag=document.querySelector("#tagPhoto");if(tag)tag.onclick=()=>{ui.captureMode="tag";document.querySelector("#tagInput").click();};const box=document.querySelector("#shoeBox");if(box)box.onclick=()=>{ui.captureMode="box";document.querySelector("#tagInput").click();};
  const tagInput=document.querySelector("#tagInput");if(tagInput)tagInput.onchange=e=>{if(ui.captureMode==="box")ui.editing.shoeBoxPhoto=true;else ui.editing.tagPhoto=true;ui.extraCandidates=[{field:"brand",label:"ブランド候補",value:ui.editing.brand||"REGAL"},{field:"subtype",label:"種類候補",value:ui.editing.subtype==="未設定"?"ローファー":ui.editing.subtype},{field:"tags",label:"タグ候補",value:ui.captureMode==="box"?"革靴":"営業"}];e.target.value="";render();};
  const suggest=document.querySelector("#suggestName");if(suggest)suggest.onclick=()=>{syncBasicEditorValues();buildNameSuggestions();render();};
  document.querySelectorAll(".name-choice").forEach(b=>b.onclick=()=>{ui.editing.name=b.dataset.name;ui.nameSuggestions=[];render();});
  document.querySelectorAll(".color-choice").forEach(b=>b.onclick=()=>{syncBasicEditorValues();ui.editing.color=b.dataset.color;ui.editing.colorConfidence=Number(b.dataset.confidence);ui.editing.colorSource="photo";ui.colorConfirmed=true;buildNameSuggestions();render();});
  const color=document.querySelector("#color");if(color)color.onchange=e=>{syncBasicEditorValues();ui.editing.color=e.target.value;ui.editing.colorConfidence=null;ui.editing.colorSource="manual";ui.colorConfirmed=true;buildNameSuggestions();render();};
  document.querySelectorAll(".type-choice").forEach(b=>b.onclick=()=>{syncBasicEditorValues();ui.editing.subtype=b.dataset.value;applySuggestedDefaults(ui.editing);buildNameSuggestions();render();});
  document.querySelectorAll(".brand-choice").forEach(b=>b.onclick=()=>{syncBasicEditorValues();ui.editing.brand=b.dataset.value;buildNameSuggestions();render();});
  document.querySelectorAll(".tag-choice").forEach(b=>b.onclick=()=>{syncBasicEditorValues();const value=b.dataset.value,tags=new Set(ui.editing.tags||[]);tags.has(value)?tags.delete(value):tags.add(value);ui.editing.tags=[...tags];render();});
  const walk=document.querySelector("#walk");if(walk)walk.oninput=e=>document.querySelector("#walkValue").textContent=e.target.value;const easy=document.querySelector("#easyOff");if(easy)easy.oninput=e=>document.querySelector("#easyOffValue").textContent=e.target.value;
  const formal=document.querySelector("#formal");if(formal)formal.oninput=e=>document.querySelector("#formalValue").textContent=e.target.value;
  const del=document.querySelector("#delete");if(del)del.onclick=()=>{if(confirm("この登録を削除しますか？")){state.items=state.items.filter(x=>x.id!==ui.editing.id);saveState();close();}};
  document.querySelector("#save").onclick=saveEditor;
}
function normalizeBrand(value){const key=String(value||"").trim(),map={"regal":"REGAL","Regal":"REGAL","スケッチャーズ":"SKECHERS","Adidas":"adidas","アディダス":"adidas","Nike":"NIKE","ナイキ":"NIKE","ユニクロ":"UNIQLO","Uniqlo":"UNIQLO","青山":"洋服の青山","オリヒカ":"ORIHICA","Orihica":"ORIHICA","エドウィン":"EDWIN","Edwin":"EDWIN"};return map[key]||key;}
function applySuggestedDefaults(i){if(i.kind==="shirt"){if(/ポロ/.test(i.subtype)){i.formal=Math.min(i.formal,3);i.sleeve="半袖";i.collar="レギュラー";}if(/Tシャツ/.test(i.subtype)){i.formal=Math.min(i.formal,3);i.collar="襟なし";}if(/ワイシャツ|ドレス|ビジネス/.test(i.subtype)){i.formal=Math.max(i.formal,4);i.collar=i.collar==="未設定"?"レギュラー":i.collar;}}if(i.kind==="pants"&&/スラックス/.test(i.subtype))i.formal=Math.max(i.formal,4);if(i.kind==="shoes"){if(/スニーカー|サンダル/.test(i.subtype))i.formal=Math.min(i.formal,3);if(/ローファー|プレーントゥ|ストレートチップ|ビジネス/.test(i.subtype))i.formal=Math.max(i.formal,4);if(/ランニング|ウォーキング/.test(i.subtype))i.walk=Math.max(i.walk,4);if(/レイン/.test(i.subtype))i.rain="good";}}
function buildNameSuggestions(){const i=ui.editing,brand=normalizeBrand(i.brand),color=i.color,type=i.subtype==="未設定"?LABEL[i.kind]:i.subtype,english=({"白":"Snow","黒":"Midnight","グレー":"Silver","ネイビー":"Navy Classic","青":"Ocean","水色":"Sky","ベージュ":"Sand","ブラウン":"Classic Brown","グリーン":"Forest","カーキ":"Olive","赤":"Ruby","ワイン":"Bordeaux","ピンク":"Rose","イエロー":"Sunny","オレンジ":"Amber","パープル":"Violet","その他":"Daily"})[color]||"Daily",style=i.kind==="shoes"?(type.includes("ローファー")?"Loafer":"Shoes"):i.kind==="shirt"?(i.pattern==="ドット"?"Dot Breeze":"Top"):"Pants";ui.nameSuggestions=[`${brand?brand+" ":""}${color}${type}`,`${english} ${style}`,`${color} ${type} Style`,i.formal>=4?"営業エース":"休日の相棒",color==="黒"?"黒王":i.kind==="shirt"?"今日の一枚":"今日は君だ"];
}
function bindBoxEditor(){const close=()=>{ui.boxEditing=null;render();};document.querySelector("#closeBox").onclick=close;const pick=id=>document.querySelector(id).click();document.querySelector("#boxCamera").onclick=()=>pick("#boxCameraInput");document.querySelector("#boxLibrary").onclick=()=>pick("#boxLibraryInput");const changed=async e=>{const file=e.target.files?.[0];if(!file)return;ui.boxEditing.image=await compressImage(file);const candidates=await analyzeColor(file);ui.boxEditing.color=candidates[0]?.name||"その他";render();};document.querySelector("#boxCameraInput").onchange=changed;document.querySelector("#boxLibraryInput").onchange=changed;document.querySelector("#saveBox").onclick=()=>{const b=ui.boxEditing;b.brand=normalizeBrand(document.querySelector("#boxBrand").value.trim());b.productName=document.querySelector("#boxProductName").value.trim();b.modelNumber=document.querySelector("#boxModelNumber").value.trim();b.color=document.querySelector("#boxColor").value;b.linkedShoeId=document.querySelector("#linkedShoeId").value;b.memo=document.querySelector("#boxMemo").value.trim();const n=state.boxes.findIndex(x=>x.id===b.id);n>=0?state.boxes[n]=b:state.boxes.push(b);saveState();close();};document.querySelector("#deleteBox").onclick=()=>{const exists=state.boxes.some(x=>x.id===ui.boxEditing.id);if(!exists)return close();if(confirm("この靴箱登録を削除しますか？")){state.boxes=state.boxes.filter(x=>x.id!==ui.boxEditing.id);saveState();close();}};}
function bindRegistrationDone(){const item=ui.registrationDone,close=()=>{ui.registrationDone=null;ui.tab="master";render();};document.querySelector("#doneMaster").onclick=close;document.querySelector("#doneAnother").onclick=()=>{const kind=item.kind;ui.registrationDone=null;ui.colorCandidates=[];ui.nameSuggestions=[];ui.editing=makeItem(kind);render();};document.querySelector("#doneKarte").onclick=()=>{ui.registrationDone=null;ui.tab="master";ui.kind=item.kind;ui.karte=find(item.id);render();};document.querySelector("#doneToday").onclick=()=>{ui.registrationDone=null;ui.tab="today";if(item.kind==="shirt")ui.shirtId=item.id;if(item.kind==="pants")ui.pantsId=item.id;render();};}
function bindKarte(){const close=()=>{ui.karte=null;render();};document.querySelector("#closeKarte").onclick=close;document.querySelectorAll(".maintenance-action").forEach(b=>b.onclick=()=>{const item=find(ui.karte.id),record={id:crypto.randomUUID(),date:today(),type:b.dataset.type};item.maintenanceHistory=[record,...(item.maintenanceHistory||[])];item.maintenanceDate=record.date;item.maintenanceCount=(item.maintenanceCount||0)+1;ui.karte=item;saveState();render();});const wear=document.querySelector("#wearFromKarte");if(wear)wear.onclick=()=>{const item=ui.karte;ui.karte=null;ui.tab="today";recordWear(item.id,"カルテから今日履くを選択");};document.querySelector("#historyFromKarte").onclick=()=>{ui.karte=null;ui.tab="history";render();};document.querySelector("#editFromKarte").onclick=()=>{const item=structuredClone(ui.karte);ui.karte=null;ui.nameSuggestions=[];ui.extraCandidates=[];ui.editing=item;render();};}
function syncBasicEditorValues(){const i=ui.editing;i.name=document.querySelector("#name")?.value.trim()||i.name;i.brand=normalizeBrand(document.querySelector("#brand")?.value||i.brand);i.color=document.querySelector("#color")?.value||i.color;i.secondaryColor=document.querySelector("#secondaryColor")?.value||i.secondaryColor||"";i.subtype=document.querySelector("#subtype")?.value.trim()||i.subtype||"未設定";const tagInput=document.querySelector("#tags");if(tagInput)i.tags=tagInput.value.split(/[、,]/).map(x=>x.trim()).filter(Boolean);}
async function photoChanged(e){const file=e.target.files?.[0];if(!file)return;ui.editing.image=await compressImage(file);ui.colorCandidates=await analyzeColor(file);ui.colorConfirmed=false;const top=ui.colorCandidates[0];if(top){ui.editing.color=top.name;ui.editing.colorConfidence=top.confidence;ui.editing.colorSource="photo";}if(!ui.editing.name)ui.editing.name=`${ui.editing.color}${ui.editing.subtype==="未設定"?LABEL[ui.editing.kind]:ui.editing.subtype}`;buildNameSuggestions();render();}
function saveEditor(){const i=ui.editing,exists=state.items.some(x=>x.id===i.id);syncBasicEditorValues();i.brand=normalizeBrand(i.brand);i.formal=Number(document.querySelector("#formal")?.value||i.formal);i.favorite=!!document.querySelector("#favorite")?.checked;i.productName=document.querySelector("#productName")?.value.trim()||"";i.modelNumber=document.querySelector("#modelNumber")?.value.trim()||"";i.store=document.querySelector("#store")?.value.trim()||"";i.purchaseDate=document.querySelector("#purchaseDate")?.value||"";i.price=document.querySelector("#price")?.value.trim()||"";i.productURL=document.querySelector("#productURL")?.value.trim()||"";i.memo=document.querySelector("#memo")?.value.trim()||"";document.querySelectorAll(".candidate:checked").forEach(c=>{const candidate=ui.extraCandidates[Number(c.dataset.index)];if(candidate.field==="tags")i.tags=[...new Set([...i.tags,candidate.value])];else i[candidate.field]=candidate.value;});if(i.kind==="shirt"){i.sleeve=document.querySelector("#sleeve")?.value||i.sleeve;i.collar=document.querySelector("#collar")?.value||i.collar;i.pattern=document.querySelector("#pattern")?.value||i.pattern;i.fit=document.querySelector("#fit")?.value||i.fit;}if(i.kind==="pants"){i.length=document.querySelector("#length")?.value||i.length;i.pattern=document.querySelector("#pattern")?.value||i.pattern;i.fit=document.querySelector("#fit")?.value||i.fit;}if(i.kind==="shoes"){i.material=document.querySelector("#material")?.value||i.material;i.rain=document.querySelector("#rain")?.value||i.rain;i.walk=Number(document.querySelector("#walk")?.value||i.walk);i.easyOff=Number(document.querySelector("#easyOff")?.value||i.easyOff);}if(!i.name)i.name=`${i.color}${i.subtype==="未設定"?LABEL[i.kind]:i.subtype}`;if(ui.colorCandidates.length&&!ui.colorConfirmed)return alert("写真の色候補から実物に近い色をタップしてください。");if(!i.color||i.color==="その他")return alert("実物に近い色を選んでください。");if(!i.subtype||i.subtype==="未設定")return alert("種類を選んでください。");const n=state.items.findIndex(x=>x.id===i.id);n>=0?state.items[n]=i:state.items.push(i);saveState();ui.editing=null;ui.nameSuggestions=[];ui.extraCandidates=[];ui.colorCandidates=[];ui.colorConfirmed=false;if(exists){render();}else{ui.registrationDone=structuredClone(i);render();}}

function compressImage(file){return new Promise((resolve,reject)=>{const reader=new FileReader();reader.onerror=reject;reader.onload=()=>{const img=new Image();img.onload=()=>{const max=1000,scale=Math.min(1,max/Math.max(img.width,img.height)),canvas=document.createElement("canvas");canvas.width=Math.round(img.width*scale);canvas.height=Math.round(img.height*scale);canvas.getContext("2d").drawImage(img,0,0,canvas.width,canvas.height);resolve(canvas.toDataURL("image/jpeg",.76));};img.src=reader.result;};reader.readAsDataURL(file);});}
function rgbToHsv(r,g,b){r/=255;g/=255;b/=255;const max=Math.max(r,g,b),min=Math.min(r,g,b),d=max-min;let h=0;if(d){if(max===r)h=60*(((g-b)/d)%6);else if(max===g)h=60*((b-r)/d+2);else h=60*((r-g)/d+4);}if(h<0)h+=360;return{h,s:max?d/max:0,v:max};}
function colorFamily(r,g,b){const {h,s,v}=rgbToHsv(r,g,b);if(v<.18)return"黒";if(s<.12&&v>.84)return"白";if(s<.16)return"グレー";if(h<12||h>=345){if(v<.45)return"ワイン";return s<.5?"ピンク":"赤";}if(h<28)return v<.55?"ブラウン":"オレンジ";if(h<48)return v<.55?"ブラウン":s<.42?"ベージュ":"オレンジ";if(h<68)return s<.36?"ベージュ":"イエロー";if(h<90)return v<.55?"カーキ":"イエロー";if(h<155)return v<.48||h<105?"カーキ":"グリーン";if(h<195)return v>.72?"水色":"グリーン";if(h<245)return v<.42?"ネイビー":v>.72&&s<.55?"水色":"青";if(h<285)return v<.42?"ネイビー":"パープル";if(h<330)return s<.5?"ピンク":"パープル";return v<.45?"ワイン":"ピンク";}
async function analyzeColor(file){try{const bitmap=await createImageBitmap(file),size=64,canvas=document.createElement("canvas");canvas.width=size;canvas.height=size;const ctx=canvas.getContext("2d",{willReadFrequently:true});ctx.drawImage(bitmap,0,0,size,size);const d=ctx.getImageData(0,0,size,size).data,cornerPoints=[[2,2],[61,2],[2,61],[61,61]],background=cornerPoints.map(([x,y])=>{const n=(y*size+x)*4;return[d[n],d[n+1],d[n+2]];}),scores={},centerMin=size*.15,centerMax=size*.85;let total=0;for(let y=0;y<size;y++){for(let x=0;x<size;x++){const n=(y*size+x)*4,a=d[n+3];if(a<100)continue;const r=d[n],g=d[n+1],b=d[n+2],distance=Math.min(...background.map(c=>Math.hypot(r-c[0],g-c[1],b-c[2]))),central=x>=centerMin&&x<=centerMax&&y>=centerMin&&y<=centerMax;let weight=central?2.4:.65;if(distance<24)weight*=.12;else if(distance<45)weight*=.45;const {v}=rgbToHsv(r,g,b);if(v<.04||v>.985)weight*=.25;if(weight<.05)continue;const family=colorFamily(r,g,b);scores[family]=(scores[family]||0)+weight;total+=weight;}}const ranked=Object.entries(scores).sort((a,b)=>b[1]-a[1]).slice(0,3);if(!ranked.length)return[];const topTotal=ranked.reduce((sum,x)=>sum+x[1],0);return ranked.map(([name,value])=>({name,confidence:Math.max(1,Math.round(value/topTotal*100))}));}catch(e){return[];}}

async function loadWeather(){const fallback=()=>{weather={area:"現在地",condition:"晴れ",temperature:28,rainChance:20,yesterday:"取得できませんでした"};render();};if(!navigator.geolocation)return fallback();navigator.geolocation.getCurrentPosition(async p=>{try{const {latitude,longitude}=p.coords,url=`https://api.open-meteo.com/v1/forecast?latitude=${latitude}&longitude=${longitude}&current=temperature_2m,weather_code&daily=weather_code,temperature_2m_max,precipitation_probability_max&past_days=1&forecast_days=2&timezone=auto`,d=await fetch(url).then(r=>r.json()),label=c=>c>=51?"雨":c>=2?"くもり":"晴れ";weather={area:"現在地",condition:label(d.current.weather_code),temperature:Math.round(d.current.temperature_2m),rainChance:d.daily.precipitation_probability_max[1]||0,yesterday:`${label(d.daily.weather_code[0])} ${Math.round(d.daily.temperature_2m_max[0])}℃`};render();}catch(e){fallback();}},fallback,{timeout:8000});}

render();loadWeather();if("serviceWorker" in navigator)navigator.serviceWorker.register("sw.js").catch(()=>{});
